  /**
   * macOS 逐字打字 - 使用 AppleScript 循环 keystroke
   */
  async _typeMacOS(text, charDelay) {
    // 把特殊字符转义
    const escaped = text
      .replace(/\\/g, '\\\\')
      .replace(/"/g, '\\"')
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r')
      .replace(/\t/g, '\\t');

    // 一次 AppleScript 调用，循环逐字输出
    const script = `
      set theText to "${escaped}"
      set charDelay to ${charDelay} / 1000.0
      repeat with i from 1 to count of theText
        set thisChar to character i of theText
        tell application "System Events" to keystroke thisChar
        delay charDelay
      end repeat
    `;

    return new Promise((resolve, reject) => {
      const proc = spawn('osascript', ['-e', script]);
      let errorOut = '';

      proc.stderr.on('data', (d) => { errorOut += d.toString(); });

      proc.on('close', (code) => {
        if (code === 0) {
          this.safeLog('✅ macOS 逐字打字完成');
          resolve({ success: true });
        } else {
          reject(new Error(`macOS 打字失败: ${errorOut}`));
        }
      });

      proc.on('error', (err) => reject(err));
    });
  }

  /**
   * Windows 逐字打字 - 使用 PowerShell SendKeys
   */
  async _typeWindows(text, charDelay) {
    // 转义特殊字符
    const escaped = text
      .replace(/\\/g, '\\\\')
      .replace(/"/g, '\\"')
      .replace(/'/g, "''")
      .replace(/\n/g, '`n')
      .replace(/\r/g, '`r')
      .replace(/\t/g, '`t');

    const script = `
      Add-Type -AssemblyName System.Windows.Forms
      $text = "${escaped}"
      foreach ($c in $text.ToCharArray()) {
        [System.Windows.Forms.SendKeys]::SendWait($c.ToString())
        Start-Sleep -Milliseconds ${charDelay}
      }
    `;

    return new Promise((resolve, reject) => {
      const proc = spawn('powershell', [
