const filePath = path.join(__dirname, 'src', 'App.jsx');
let content = fs.readFileSync(filePath, 'utf8');

// Find safePaste function
const startMarker = '  const safePaste = useCallback(async (text) => {';
const endMarker = '  // 处理录音完成';

const startIdx = content.indexOf(startMarker);
const endIdx = content.indexOf(endMarker, startIdx);

if (startIdx === -1 || endIdx === -1) {
  console.error('Could not find markers');
  process.exit(1);
}

const newFunc = `  const safePaste = useCallback(async (text) => {
    const now = Date.now();
    const lastPaste = lastPasteRef.current;

    if (lastPaste.text === text && (now - lastPaste.timestamp) < PASTE_DEBOUNCE_TIME) {
      console.log('跳过重复粘贴', text.substring(0, 50) + '...');
      return;
    }

    lastPasteRef.current = { text, timestamp: now };

    console.log('safePaste 被调用', text.substring(0, 50) + '...', '打字模式:', typeMode);
    try {
      if (window.electronAPI) {
        if (typeMode) {
          console.log('打字模式: 逐字模拟键盘输出');
          await window.electronAPI.typeTextLikeTyping(text, 30);
          toast.success('文本已逐字输出到当前输入框');
        } else {
          await window.electronAPI.pasteText(text);
          toast.success('文本已自动粘贴到当前输入框');
        }
      } else {
        await navigator.clipboard.writeText(text);
        toast.info('文本已复制到剪贴板，请手动粘贴');
      }
    } catch (error) {
      console.error('粘贴失败:', error);
      toast.error('粘贴失败', {
        description: '文本已复制到剪贴板 - 请手动使用 Cmd+V 粘贴'
      });
    }
  }, [typeMode]);

  // 处理录音完成`;

content = content.substring(0, startIdx) + newFunc + content.substring(endIdx);

fs.writeFileSync(filePath, content, 'utf8');
console.log('safePaste function updated successfully!');
"}

