const path = require('path');

const filePath = path.join(__dirname, 'src', 'App.jsx');
let content = fs.readFileSync(filePath, 'utf8');

// Find where to insert the typing mode button
// We want to add it after the settings button in the header
// Look for the last </Tooltip> in the header area (before the second occurrence which closes the settings tooltip)

const marker1 = '<Settings className="w-6 h-6 text-gray-700 dark:text-gray-300" />';
const marker2 = 'onClick={handleOpenSettings}';

// Find the parent div that wraps the buttons - look for the closing </div> of the button group
// We'll insert after the settings Tooltip closes

// Strategy: Find the line with Settings icon button, then find the closing </Tooltip> after it
const settingsIdx = content.indexOf('<Settings className=');
const tooltipCloseAfterSettings = content.indexOf('</Tooltip>', settingsIdx);
const buttonGroupEnd = content.indexOf('          </div>', tooltipCloseAfterSettings);

const typeBtnHtml = `            <Tooltip content={typeMode ? '打字模式已开启：逐字输出' : '普通模式：一次性粘贴'} position="bottom">
              <button
                onClick={() => setTypeMode(!typeMode)}
                className={\`p-3 rounded-xl transition-colors shadow-sm \${
                  typeMode
                    ? 'bg-emerald-100 dark:bg-emerald-800 text-emerald-600 dark:text-emerald-400'
                    : 'hover:bg-white/70 dark:hover:bg-gray-700/70 text-gray-700 dark:text-gray-300'
                }\`}
                title={typeMode ? '打字模式' : '普通模式'}
              >
                <Keyboard className="w-6 h-6" />
              </button>
            </Tooltip>
`;

content = content.substring(0, tooltipCloseAfterSettings + '</Tooltip>'.length) + '\n' + typeBtnHtml + content.substring(tooltipCloseAfterSettings + '</Tooltip>'.length);

fs.writeFileSync(filePath, content, 'utf8');
console.log('Typing mode button added successfully!');
"}

